from pyro.geometry import distance
from pyro.brain.behaviors.fsm import State, FSMBrain
class edge(State):
def onActivate(self):
self.startX = self.get('robot/x')
self.startY = self.get('robot/y')
def update(self):
x = self.get('robot/x')
y = self.get('robot/y')
dist = distance( self.startX, self.startY, x, y)
if dist > 1.0:
self.goto('turn')
else:
self.robot.move(.3, 0)
